#include <stdio.h>

struct Proizvod {
    char naziv[20];
    int sifra;
    float cijena;
};

int main() {
    FILE *f = fopen("proizvodi.dat", "rb");
    if (f == NULL) {
        printf("Greska: ne mogu otvoriti proizvodi.dat\n");
        return 1;
    }

    struct Proizvod p;
    int ukupno = 0;

    float maxCijena = -1.0f;
    struct Proizvod najskuplji;

    while (fread(&p, sizeof(struct Proizvod), 1, f) == 1) {
        ukupno++;
        if (p.cijena > maxCijena) {
            maxCijena = p.cijena;
            najskuplji = p;
        }
    }

    fclose(f);

    if (ukupno == 0) {
        printf("Datoteka je prazna.\n");
        return 0;
    }

    printf("Ukupno proizvoda: %d\n", ukupno);
    printf("Najskuplji: %s | sifra: %d | cijena: %.2f\n",
           najskuplji.naziv, najskuplji.sifra, najskuplji.cijena);

    return 0;
}
